import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = edge_distance.copy()
    penalty_factor = 0.1

    for tour in local_opt_tours:
        for i in range(len(tour)-1):
            edge_id = (tour[i], tour[i+1])
            updated_edge_distance[edge_id[0], edge_id[1]] += penalty_factor * edge_n_used[edge_id[0], edge_id[1]]
            updated_edge_distance[edge_id[1], edge_id[0]] += penalty_factor * edge_n_used[edge_id[1], edge_id[0]]

    return updated_edge_distance
